// Validate incoming payload
const body = $input.first().json.body || $input.first().json;

if (!body.file_content && !body.file_url) {
  throw new Error('Missing file_content or file_url in request body');
}

const document_id = body.document_id || body.session_id || `doc_${Date.now()}_${Math.random().toString(36).substr(2, 8)}`;

const inferFileType = (url, name) => {
  const source = url || name || '';
  const ext = source.split('.').pop().toLowerCase().split('?')[0];
  const allowed = ['pdf', 'docx', 'xlsx', 'pptx', 'txt'];
  return allowed.includes(ext) ? ext : null;
};

const fileType = (body.file_type || '').toLowerCase() || inferFileType(body.file_url, body.file_name);

const allowedTypes = ['pdf', 'docx', 'xlsx', 'pptx', 'txt'];
if (!fileType || !allowedTypes.includes(fileType)) {
  throw new Error(`Cannot determine file type. Provide file_type explicitly. Allowed: ${allowedTypes.join(', ')}`);
}

const namespace = body.namespace || 'gda-documents';

return [{
  json: {
    document_id,
    file_content: body.file_content || null,
    file_url: body.file_url || null,
    file_type: fileType,
    file_name: body.file_name || body.file_url?.split('/').pop() || 'unknown',
    namespace,
    metadata: {
      uploaded_by: body.uploaded_by || 'unknown',
      source: body.source || 'manual_upload',
      classification: body.classification || 'UNCLASSIFIED',
      upload_timestamp: new Date().toISOString(),
      document_id,
      namespace
    }
  }
}];

// Extract text from base64-encoded file content
// Handles the case where file is sent directly (not via URL)
const item = $input.first().json;

if (item.file_content) {
  // File sent as base64
  const buffer = Buffer.from(item.file_content, 'base64');
  // For text files, decode directly
  // For binary formats, this is a placeholder - use document loader node instead
  const text = buffer.toString('utf-8');
  return [{ json: { ...item, raw_text: text } }];
}

// If coming from URL fetch, binary data is in $binary
return [{ json: item }];

// Merge extracted text - filter out error items, return error item if nothing valid
const items = $input.all();
const results = [];

// Get metadata from Validate & Extract Input as fallback
let validateData = {};
try { validateData = $('Validate & Extract Input').first().json; } catch(e) {}

for (const item of items) {
  // Skip error items from failed branches (URL fetch failed, no binary, etc.)
  if (item.json.error && !item.json.document_id) {
    continue;
  }

  // extractFromFile text operation returns text in 'data'; pdf returns in 'text'
  const text = item.json.text || item.json.raw_text || item.json.content || item.json.data || '';

  if (!text || text.trim().length === 0) {
    continue; // Skip empty items
  }

  // Fall back to Validate & Extract Input for metadata when extractFromFile doesn't pass it through
  const docId = item.json.document_id || validateData.document_id || 'unknown';
  const fileName = item.json.file_name || item.json.filename || validateData.file_name || 'unknown';
  const fileType = item.json.file_type || validateData.file_type || 'unknown';
  const namespace = item.json.namespace || validateData.namespace || 'gda-documents';

  results.push({
    json: {
      document_id: docId,
      file_name: fileName,
      file_type: fileType,
      namespace,
      extracted_text: text.trim(),
      extraction_status: 'success',
      char_count: text.trim().length,
      metadata: item.json.metadata || validateData.metadata || {}
    }
  });
}

// If no valid text was found, return error item instead of empty array
// This ensures Respond to Webhook is always reached
if (results.length === 0) {
  const firstItem = items[0]?.json || {};
  return [{
    json: {
      document_id: firstItem.document_id || validateData.document_id || 'unknown',
      file_name: firstItem.file_name || firstItem.filename || validateData.file_name || 'unknown',
      file_type: firstItem.file_type || validateData.file_type || 'unknown',
      extraction_status: 'failed',
      extracted_text: '',
      char_count: 0,
      error: 'No text could be extracted from the document. Check file URL accessibility or file format.'
    }
  }];
}

return results;

// Split text into chunks for embedding
// Uses overlapping windows to preserve context across chunk boundaries
const item = $input.first().json;

if (item.extraction_status === 'failed') {
  return [{ json: item }];
}

const text = item.extracted_text;
const chunkSize = 1000;      // characters per chunk
const chunkOverlap = 200;    // overlap between chunks

const chunks = [];
let start = 0;
let chunkIndex = 0;

while (start < text.length) {
  const end = Math.min(start + chunkSize, text.length);
  const chunkText = text.slice(start, end).trim();

  if (chunkText.length > 50) { // Skip tiny chunks
    chunks.push({
      chunk_id: `${item.document_id}_chunk_${chunkIndex}`,
      document_id: item.document_id,
      file_name: item.file_name,
      chunk_index: chunkIndex,
      total_chunks: Math.ceil(text.length / (chunkSize - chunkOverlap)),
      text: chunkText,
      metadata: {
        ...item.metadata,
        chunk_index: chunkIndex,
        chunk_id: `${item.document_id}_chunk_${chunkIndex}`
      }
    });
    chunkIndex++;
  }

  start += chunkSize - chunkOverlap;
}

// Return each chunk as a separate item for parallel embedding
return chunks.map(chunk => ({ json: chunk }));

