// Collect all chunk upsert results and build final status
const items = $input.all();

const successful = items.filter(i => i.json.upsertedCount > 0 || i.json.upsertedCount === 0).length;
const failed = items.filter(i => i.json.error).length;

// Get document metadata from the upstream validation node
const validatedInput = $('Validate & Extract Input').first().json;
const documentId = validatedInput.document_id || items[0]?.json.document_id || 'unknown';
const fileName = validatedInput.file_name || items[0]?.json.file_name || 'unknown';

return [{
  json: {
    status: failed === 0 ? 'success' : 'partial_failure',
    document_id: documentId,
    file_name: fileName,
    chunks_processed: items.length,
    chunks_succeeded: successful,
    chunks_failed: failed,
    message: `Document '${fileName}' successfully ingested. ${successful} chunks stored in Pinecone.`,
    timestamp: new Date().toISOString()
  }
}];

const body = $input.first().json.body || $input.first().json;

if (!body.query || body.query.trim().length === 0) {
  throw new Error('Missing query text');
}

return [{
  json: {
    query: body.query.trim(),
    session_id: body.session_id || 'default',
    top_k: body.top_k || 5,
    namespace: body.namespace || 'gda-documents',
    filter: body.filter || null,
    timestamp: new Date().toISOString()
  }
}];

