const pineconeResult = $input.first().json;
const queryData = $('Validate Query Input').first().json;

const matches = pineconeResult.matches || [];

if (matches.length === 0) {
  return [{
    json: {
      query: queryData.query,
      context_found: false,
      context_text: '',
      citations: [],
      message: 'Data Unavailable - No relevant documents found in knowledge base.'
    }
  }];
}

// Build numbered citation blocks
const citations = matches.map((match, idx) => ({
  citation_number: idx + 1,
  chunk_id: match.id,
  document_id: match.metadata?.document_id || 'unknown',
  file_name: match.metadata?.file_name || 'unknown',
  relevance_score: Math.round(match.score * 100) / 100,
  text: match.metadata?.text || 'Data Unavailable'
}));

// Build context block for Claude
const contextText = citations
  .map(c => `[SOURCE ${c.citation_number}: ${c.file_name} | Score: ${c.relevance_score}]\n${c.text}`)
  .join('\n\n---\n\n');

return [{
  json: {
    query: queryData.query,
    session_id: queryData.session_id,
    context_found: true,
    context_text: contextText,
    citations: citations,
    timestamp: queryData.timestamp
  }
}];

const claudeResponse = $input.first().json;
const contextData = $('Build RAG Context').first().json;

if (!contextData.context_found) {
  return [{
    json: {
      status: 'no_data',
      query: contextData.query,
      answer: 'Data Unavailable - No relevant documents found in knowledge base.',
      citations: [],
      timestamp: contextData.timestamp
    }
  }];
}

const answer = claudeResponse.content?.[0]?.text || 'Data Unavailable';

return [{
  json: {
    status: 'success',
    query: contextData.query,
    session_id: contextData.session_id,
    answer: answer,
    citations: contextData.citations.map(c => ({
      number: c.citation_number,
      file_name: c.file_name,
      document_id: c.document_id,
      relevance_score: c.relevance_score,
      excerpt: c.text.substring(0, 300) + (c.text.length > 300 ? '...' : '')
    })),
    model_used: 'claude-sonnet-4-5',
    timestamp: contextData.timestamp
  }
}];

const body = $input.first().json.body || $input.first().json;

if (!body.rfp_text && !body.document_id) {
  throw new Error('Missing rfp_text or document_id');
}

return [{
  json: {
    rfp_text: body.rfp_text || null,
    document_id: body.document_id || null,
    rfp_title: body.rfp_title || 'Untitled RFP',
    agency: body.agency || 'Unknown Agency',
    session_id: body.session_id || `redteam_${Date.now()}`,
    callback_url: body.callback_url || null,
    timestamp: new Date().toISOString()
  }
}];

