// Safely parse Claude JSON responses - handles markdown-wrapped JSON
function parseClaudeResponse(response) {
  try {
    const text = response?.content?.[0]?.text || '';
    const jsonMatch = text.match(/```(?:json)?\s*([\s\S]*?)\s*```/);
    if (jsonMatch) {
      return JSON.parse(jsonMatch[1]);
    }
    const start = text.indexOf('{');
    const end = text.lastIndexOf('}');
    if (start !== -1 && end !== -1) {
      return JSON.parse(text.substring(start, end + 1));
    }
    return JSON.parse(text);
  } catch (e) {
    return { error: 'Parse failed', raw: (response?.content?.[0]?.text || '').substring(0, 500) };
  }
}

const legalRaw = $('Legal Review').first().json;
const commercialRaw = $('Commercial Review').first().json;
const blackhatRaw = $('Black Hat Review').first().json;
const opsRaw = $('Operational Review').first().json;
const riskRaw = $('5C + 4C Risk Assessment').first().json;
const inputData = $('Validate RFP Input').first().json;

const legal = parseClaudeResponse(legalRaw);
const commercial = parseClaudeResponse(commercialRaw);
const blackhat = parseClaudeResponse(blackhatRaw);
const ops = parseClaudeResponse(opsRaw);
const risk = parseClaudeResponse(riskRaw);

// Build overall risk score from 5C scores
let overallScore = 'Data Unavailable';
let winPct = 'Data Unavailable';
try {
  const scores = Object.values(risk.five_cs || {}).map(c => c.score).filter(s => typeof s === 'number');
  if (scores.length > 0) {
    const avg = scores.reduce((a, b) => a + b, 0) / scores.length;
    overallScore = avg.toFixed(1) + '/5';
    winPct = Math.round((avg / 5) * 100) + '%';
  }
} catch(e) {}

const goNoGo = commercial.go_no_go?.recommendation || commercial.go_no_go || 'Data Unavailable';

const summary = [
  inputData.rfp_title ? 'RFP: ' + inputData.rfp_title : '',
  inputData.agency ? 'Agency: ' + inputData.agency : '',
  'Risk Score: ' + overallScore,
  'Go/No-Go: ' + goNoGo,
  commercial.rationale ? 'Rationale: ' + commercial.rationale : ''
].filter(Boolean).join(' | ');

const technical = {
  execution_risks: ops.execution_risks || 'Data Unavailable',
  staffing_requirements: ops.staffing_requirements || 'Data Unavailable',
  timeline_assessment: ops.timeline_assessment || 'Data Unavailable',
  supply_chain_risks: ops.supply_chain_risks || 'Data Unavailable',
  performance_metrics: ops.performance_metrics || 'Data Unavailable'
};

const compliance_out = {
  compliance_issues: legal.compliance_issues || [],
  high_risk_clauses: legal.high_risk_clauses || [],
  missing_provisions: legal.missing_provisions || [],
  recommendations: legal.recommendations || []
};

const risk_out = {
  five_cs: risk.five_cs || {},
  four_cs: risk.four_cs || {},
  overall_score: overallScore,
  high_risk_clauses: legal.high_risk_clauses || []
};

const price = {
  profitability: commercial.profitability || 'Data Unavailable',
  resource_requirements: commercial.resource_requirements || 'Data Unavailable',
  business_value: commercial.business_value || 'Data Unavailable'
};

const recommendation = {
  go_no_go: goNoGo,
  rationale: commercial.rationale || 'Data Unavailable',
  legal_actions: legal.recommendations || [],
  competitive_strategy: {
    likely_winner: blackhat.likely_winner || 'Data Unavailable',
    advantages_to_exploit: blackhat.competitive_advantages || [],
    protest_grounds: blackhat.protest_grounds || [],
    setaside_opportunities: blackhat.setaside_opportunities || []
  }
};

return [{
  json: {
    // Flat UI keys (what Base44 frontend expects)
    summary,
    win_probability: winPct,
    technical,
    risk: risk_out,
    compliance: compliance_out,
    price,
    recommendation,

    // Full structure (preserved for export and callback)
    status: 'complete',
    session_id: inputData.session_id,
    rfp_title: inputData.rfp_title,
    agency: inputData.agency,
    analysis_timestamp: new Date().toISOString(),
    overall_risk_score: overallScore,
    go_no_go: goNoGo,
    reviews: {
      legal,
      commercial,
      black_hat: blackhat,
      operational: ops,
      contract_risk: risk
    },
    callback_url: inputData.callback_url
  }
}];

const body = $input.first().json.body || $input.first().json;

const validActions = ['ingest', 'query', 'redteam', 'export', 'status'];

if (!body.action) throw new Error('Missing action. Valid: ' + validActions.join(', '));
if (!validActions.includes(body.action)) throw new Error('Invalid action: ' + body.action);

const sessionId = `gda_${body.action}_${Date.now()}_${Math.random().toString(36).substr(2, 6)}`;

// Support both nested payload:{...} and flat structure (fileUrl, fileName, namespace, etc at top level)
const { action, callback_url, user_id, payload: explicitPayload, ...rest } = body;

return [{
  json: {
    action,
    session_id: sessionId,
    payload: explicitPayload || rest,
    callback_url: callback_url || null,
    user_id: user_id || 'anonymous',
    timestamp: new Date().toISOString()
  }
}];

const body = $input.first().json.body || $input.first().json;

// Accept both formats: {data, export_type} OR {content, type} (Base44 presentation format)
const rawData = body.data || body.content || body.slides_data || body.topic || null;
const rawType = (body.export_type || body.type || 'word').toLowerCase();

// Map aliases
const typeMap = { presentation: 'word', pptx: 'word', doc: 'word', docx: 'word', csv: 'excel', xlsx: 'excel' };
const export_type = typeMap[rawType] || rawType;

if (!rawData && export_type !== 'word') throw new Error('Missing data/content payload');
if (!['word', 'excel'].includes(export_type)) throw new Error(`Invalid export_type. Must be: word, excel, presentation`);

return [{
  json: {
    export_type,
    is_presentation: rawType === 'presentation' || rawType === 'pptx',
    data: (typeof rawData === 'string') ? { text_content: rawData, is_text: true } : (rawData || {}),
    title: body.title || 'GDA Analysis Report',
    agency: body.agency || 'Unknown Agency',
    classification: body.classification || 'UNCLASSIFIED',
    session_id: body.session_id || `export_${Date.now()}`,
    callback_url: body.callback_url || null,
    timestamp: new Date().toISOString()
  }
}];

const item = $input.first().json;
const data = item.data;
const isPresentation = item.is_presentation || data.is_text;
const timestamp = new Date().toLocaleDateString('en-US', { year: 'numeric', month: 'long', day: 'numeric' });

let html = '';

if (isPresentation || data.is_text) {
  // Plain text / presentation content mode
  const textContent = data.text_content || JSON.stringify(data);
  const lines = textContent.split('\n').filter(l => l.trim());

  html = `<!DOCTYPE html><html><head><meta charset="UTF-8"><title>${item.title}</title>
<style>
body { font-family: Calibri, Arial, sans-serif; margin: 40px; color: #1a1a1a; background: #fff; }
h1 { color: #1B3A6B; border-bottom: 3px solid #1B3A6B; padding-bottom: 10px; font-size: 28px; }
h2 { color: #1B3A6B; margin-top: 30px; border-left: 4px solid #C8A84B; padding-left: 10px; font-size: 18px; }
p { line-height: 1.7; margin: 8px 0; }
.meta { color: #666; font-size: 13px; margin-bottom: 30px; }
.classification { background: #1a6b1a; color: white; padding: 4px 12px; border-radius: 4px; font-size: 12px; font-weight: bold; }
.slide { page-break-before: always; border: 1px solid #ddd; padding: 24px; margin: 20px 0; border-radius: 8px; }
</style></head><body>
<h1>${item.title}</h1>
<p class="meta">${item.agency} &nbsp;|&nbsp; ${timestamp} &nbsp;|&nbsp; <span class="classification">${item.classification}</span></p>
`;

  let currentSlide = null;
  for (const line of lines) {
    const trimmed = line.trim();
    if (trimmed.startsWith('# ')) {
      if (currentSlide) html += '</div>';
      currentSlide = true;
      html += `<div class="slide"><h1 style="font-size:22px;">${trimmed.slice(2)}</h1>`;
    } else if (trimmed.startsWith('## ')) {
      html += `<h2>${trimmed.slice(3)}</h2>`;
    } else if (trimmed.startsWith('- ') || trimmed.startsWith('* ')) {
      html += `<p>&#8226; ${trimmed.slice(2)}</p>`;
    } else if (trimmed) {
      html += `<p>${trimmed}</p>`;
    }
  }
  if (currentSlide) html += '</div>';
  html += '</body></html>';

} else {
  // Structured review data mode (original)
  const reviews = data.reviews || {};

  html = `<!DOCTYPE html><html><head><meta charset="UTF-8"><title>${item.title}</title>
<style>
body { font-family: Arial, sans-serif; margin: 40px; color: #1a1a1a; }
h1 { color: #1B3A6B; border-bottom: 3px solid #1B3A6B; padding-bottom: 10px; }
h2 { color: #1B3A6B; margin-top: 30px; border-left: 4px solid #C8A84B; padding-left: 10px; }
h3 { color: #333; margin-top: 20px; }
table { border-collapse: collapse; width: 100%; margin: 15px 0; }
th { background: #1B3A6B; color: white; padding: 10px; text-align: left; }
td { border: 1px solid #ddd; padding: 8px; vertical-align: top; }
tr:nth-child(even) { background: #f5f5f5; }
.risk-high { color: #cc0000; font-weight: bold; }
.risk-med { color: #cc6600; font-weight: bold; }
.risk-low { color: #006600; font-weight: bold; }
.classification { background: #1a6b1a; color: white; padding: 4px 12px; border-radius: 4px; font-size: 12px; }
.header-meta { color: #666; font-size: 13px; margin-bottom: 30px; }
</style></head><body>
<h1>GDA Analysis: ${item.title}</h1>
<p class="header-meta">${item.agency} | Generated: ${timestamp} | <span class="classification">${item.classification}</span></p>
`;

  // Executive summary
  if (data.overall_risk_score !== undefined) {
    html += `<h2>Executive Summary</h2>
<table><tr><th>Field</th><th>Value</th></tr>
<tr><td>Overall Risk Score</td><td>${data.overall_risk_score || 'N/A'}</td></tr>
<tr><td>Go / No-Go</td><td>${data.go_no_go || 'N/A'}</td></tr>
<tr><td>Bid Confidence</td><td>${data.bid_confidence || 'N/A'}</td></tr>
</table>`;
  }

  // Reviews
  for (const [reviewName, reviewData] of Object.entries(reviews)) {
    if (!reviewData) continue;
    html += `<h2>${reviewName.replace(/_/g, ' ').toUpperCase()}</h2>`;
    if (typeof reviewData === 'string') {
      html += `<p>${reviewData}</p>`;
    } else if (typeof reviewData === 'object') {
      html += '<table><tr><th>Field</th><th>Value</th></tr>';
      for (const [k, v] of Object.entries(reviewData)) {
        const val = Array.isArray(v) ? v.join('; ') : String(v || 'N/A');
        html += `<tr><td>${k.replace(/_/g, ' ')}</td><td>${val}</td></tr>`;
      }
      html += '</table>';
    }
  }

  html += '</body></html>';
}

return [{ json: { ...item, html_content: html } }];

const item = $input.first().json;
const data = item.data;
const reviews = data.reviews || {};

// Build Excel data as array of sheets
const sheets = [];

// Sheet 1: Executive Summary
sheets.push({
  name: 'Executive Summary',
  rows: [
    ['GDA Analysis Report', '', '', ''],
    ['Title', item.title, '', ''],
    ['Agency', item.agency, '', ''],
    ['Classification', item.classification, '', ''],
    ['Generated', item.timestamp, '', ''],
    ['', '', '', ''],
    ['OVERALL RISK SCORE', data.overall_risk_score || 'Data Unavailable', '', ''],
    ['GO / NO-GO', data.go_no_go || 'Data Unavailable', '', ''],
  ]
});

// Sheet 2: Legal Review
function flattenToRows(obj, prefix = '') {
  const rows = [];
  if (!obj || obj.error) {
    rows.push(['Data Unavailable', '']);
    return rows;
  }
  for (const [key, value] of Object.entries(obj)) {
    const label = (prefix ? prefix + ' > ' : '') + key.replace(/_/g, ' ');
    if (Array.isArray(value)) {
      rows.push([label, value.join('; ')]);
    } else if (typeof value === 'object' && value !== null) {
      rows.push(...flattenToRows(value, label));
    } else {
      rows.push([label, String(value)]);
    }
  }
  return rows;
}

if (reviews.legal) {
  sheets.push({
    name: 'Legal Review',
    rows: [['Field', 'Finding'], ...flattenToRows(reviews.legal)]
  });
}

if (reviews.commercial) {
