if(rows.length===0){
  const c=d.ai_content||d.html_content||d.content||'';
  const lines=c.replace(/<[^>]+>/g,' ').split('\n').filter(function(l){return l.trim();});
  rows=lines.map(function(l){return {value:l.trim()};});
