const isObj=rows.length>0&&typeof rows[0]==='object'&&!Array.isArray(rows[0]);
const headers=isObj?Object.keys(rows[0]):['Value'];
function esc(v){return String(v==null?'':v).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;');}
const hRow=headers.map(function(h){return '<Cell ss:StyleID="hdr"><Data ss:Type="String">'+esc(h)+'</Data></Cell>';}).join('');
const dRows=rows.map(function(r,i){
  var cells;
