    cells=headers.map(function(h){return '<Cell'+(i%2===1?' ss:StyleID="alt"':'')+'><Data ss:Type="String">'+esc(r[h])+'</Data></Cell>';}).join('');
  } else {
    cells=(Array.isArray(r)?r:[r]).map(function(v){return '<Cell><Data ss:Type="String">'+esc(v)+'</Data></Cell>';}).join('');
  }
  return '<Row>'+cells+'</Row>';
}).join('\n');
const sheetName=esc(rawTitle).substring(0,31);
const xml='<?xml version="1.0" encoding="UTF-8"?>'
  +'<?mso-application progid="Excel.Sheet"?>'
  +'<Workbook xmlns="urn:schemas-microsoft-com:office:spreadsheet" xmlns:ss="urn:schemas-microsoft-com:office:spreadsheet">'
