.meta { color: #666; font-size: 13px; margin-bottom: 30px; }
.classification { background: #1a6b1a; color: white; padding: 4px 12px; border-radius: 4px; font-size: 12px; font-weight: bold; }
.slide { page-break-before: always; border: 1px solid #ddd; padding: 24px; margin: 20px 0; border-radius: 8px; }
</style></head><body>
<h1>${item.title}</h1>
<p class="meta">${item.agency} &nbsp;|&nbsp; ${timestamp} &nbsp;|&nbsp; <span class="classification">${item.classification}</span></p>
`;

  let currentSlide = null;
  for (const line of lines) {
    const trimmed = line.trim();
    if (trimmed.startsWith('# ')) {
      if (currentSlide) html += '</div>';
      currentSlide = true;
      html += `<div class="slide"><h1 style="font-size:22px;">${trimmed.slice(2)}</h1>`;
    } else if (trimmed.startsWith('## ')) {
      html += `<h2>${trimmed.slice(3)}</h2>`;
    } else if (trimmed.startsWith('- ') || trimmed.startsWith('* ')) {
      html += `<p>&#8226; ${trimmed.slice(2)}</p>`;
    } else if (trimmed) {
      html += `<p>${trimmed}</p>`;
    }
  }
  if (currentSlide) html += '</div>';
  html += '</body></html>';

} else {
  // Structured review data mode (original)
  const reviews = data.reviews || {};

  html = `<!DOCTYPE html><html><head><meta charset="UTF-8"><title>${item.title}</title>
<style>
body { font-family: Arial, sans-serif; margin: 40px; color: #1a1a1a; }
h1 { color: #1B3A6B; border-bottom: 3px solid #1B3A6B; padding-bottom: 10px; }
h2 { color: #1B3A6B; margin-top: 30px; border-left: 4px solid #C8A84B; padding-left: 10px; }
h3 { color: #333; margin-top: 20px; }
table { border-collapse: collapse; width: 100%; margin: 15px 0; }
th { background: #1B3A6B; color: white; padding: 10px; text-align: left; }
td { border: 1px solid #ddd; padding: 8px; vertical-align: top; }
tr:nth-child(even) { background: #f5f5f5; }
.risk-high { color: #cc0000; font-weight: bold; }
.risk-med { color: #cc6600; font-weight: bold; }
.risk-low { color: #006600; font-weight: bold; }
.classification { background: #1a6b1a; color: white; padding: 4px 12px; border-radius: 4px; font-size: 12px; }
.header-meta { color: #666; font-size: 13px; margin-bottom: 30px; }
</style></head><body>
<h1>GDA Analysis: ${item.title}</h1>
<p class="header-meta">${item.agency} | Generated: ${timestamp} | <span class="classification">${item.classification}</span></p>
`;

  // Executive summary
  if (data.overall_risk_score !== undefined) {
    html += `<h2>Executive Summary</h2>
<table><tr><th>Field</th><th>Value</th></tr>
<tr><td>Overall Risk Score</td><td>${data.overall_risk_score || 'N/A'}</td></tr>
<tr><td>Go / No-Go</td><td>${data.go_no_go || 'N/A'}</td></tr>
<tr><td>Bid Confidence</td><td>${data.bid_confidence || 'N/A'}</td></tr>
</table>`;
  }

  // Reviews
  for (const [reviewName, reviewData] of Object.entries(reviews)) {
    if (!reviewData) continue;
    html += `<h2>${reviewName.replace(/_/g, ' ').toUpperCase()}</h2>`;
    if (typeof reviewData === 'string') {
      html += `<p>${reviewData}</p>`;
    } else if (typeof reviewData === 'object') {
      html += '<table><tr><th>Field</th><th>Value</th></tr>';
      for (const [k, v] of Object.entries(reviewData)) {
        const val = Array.isArray(v) ? v.join('; ') : String(v || 'N/A');
        html += `<tr><td>${k.replace(/_/g, ' ')}</td><td>${val}</td></tr>`;
      }
      html += '</table>';
    }
  }

  html += '</body></html>';
}

return [{ json: { ...item, html_content: html } }];

const item = $input.first().json;
