// Sheet 1: Executive Summary
sheets.push({
  name: 'Executive Summary',
  rows: [
    ['GDA Analysis Report', '', '', ''],
    ['Title', item.title, '', ''],
    ['Agency', item.agency, '', ''],
    ['Classification', item.classification, '', ''],
    ['Generated', item.timestamp, '', ''],
    ['', '', '', ''],
    ['OVERALL RISK SCORE', data.overall_risk_score || 'Data Unavailable', '', ''],
    ['GO / NO-GO', data.go_no_go || 'Data Unavailable', '', ''],
  ]
});

// Sheet 2: Legal Review
function flattenToRows(obj, prefix = '') {
  const rows = [];
  if (!obj || obj.error) {
    rows.push(['Data Unavailable', '']);
    return rows;
  }
  for (const [key, value] of Object.entries(obj)) {
    const label = (prefix ? prefix + ' > ' : '') + key.replace(/_/g, ' ');
    if (Array.isArray(value)) {
      rows.push([label, value.join('; ')]);
    } else if (typeof value === 'object' && value !== null) {
      rows.push(...flattenToRows(value, label));
    } else {
      rows.push([label, String(value)]);
    }
  }
  return rows;
}

if (reviews.legal) {
  sheets.push({
    name: 'Legal Review',
    rows: [['Field', 'Finding'], ...flattenToRows(reviews.legal)]
  });
}

if (reviews.commercial) {
  sheets.push({
    name: 'Commercial Review',
    rows: [['Field', 'Finding'], ...flattenToRows(reviews.commercial)]
  });
}

if (reviews.black_hat) {
  sheets.push({
    name: 'Black Hat Review',
    rows: [['Field', 'Finding'], ...flattenToRows(reviews.black_hat)]
  });
}

if (reviews.operational) {
  sheets.push({
    name: 'Operational Review',
    rows: [['Field', 'Finding'], ...flattenToRows(reviews.operational)]
  });
}

if (reviews.contract_risk) {
  sheets.push({
    name: '5C 4C Risk',
    rows: [['Field', 'Finding'], ...flattenToRows(reviews.contract_risk)]
  });
}

// Citations sheet
