      ['#', 'Document', 'Relevance Score', 'Excerpt'],
      ...data.citations.map(c => [c.number, c.file_name, c.relevance_score, c.excerpt])
    ]
  });
}

return [{ json: { ...item, excel_sheets: sheets } }];

