const d=$input.first().json;
const rawTitle=d.title||d.export_title||'GDA Export';
const ts=new Date().toISOString().split('T')[0];
let rows=d.excel_rows||d.rows||d.data||[];
if(!Array.isArray(rows)){try{rows=JSON.parse(rows);}catch(e){rows=[];}}
if(rows.length===0){
  const c=d.ai_content||d.html_content||d.content||'';
  const lines=c.replace(/<[^>]+>/g,' ').split('\n').filter(function(l){return l.trim();});
  rows=lines.map(function(l){return {value:l.trim()};});
}
const isObj=rows.length>0&&typeof rows[0]==='object'&&!Array.isArray(rows[0]);
const headers=isObj?Object.keys(rows[0]):['Value'];
function esc(v){return String(v==null?'':v).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;');}
const hRow=headers.map(function(h){return '<Cell ss:StyleID="hdr"><Data ss:Type="String">'+esc(h)+'</Data></Cell>';}).join('');
const dRows=rows.map(function(r,i){
  var cells;
  if(isObj){
    cells=headers.map(function(h){return '<Cell'+(i%2===1?' ss:StyleID="alt"':'')+'><Data ss:Type="String">'+esc(r[h])+'</Data></Cell>';}).join('');
  } else {
    cells=(Array.isArray(r)?r:[r]).map(function(v){return '<Cell><Data ss:Type="String">'+esc(v)+'</Data></Cell>';}).join('');
  }
  return '<Row>'+cells+'</Row>';
}).join('\n');
const sheetName=esc(rawTitle).substring(0,31);
const xml='<?xml version="1.0" encoding="UTF-8"?>'
  +'<?mso-application progid="Excel.Sheet"?>'
  +'<Workbook xmlns="urn:schemas-microsoft-com:office:spreadsheet" xmlns:ss="urn:schemas-microsoft-com:office:spreadsheet">'
  +'<Styles>'
  +'<Style ss:ID="hdr"><Font ss:Bold="1" ss:Color="#FFFFFF"/><Interior ss:Color="#1B3A6B" ss:Pattern="Solid"/></Style>'
  +'<Style ss:ID="alt"><Interior ss:Color="#F5F5F5" ss:Pattern="Solid"/></Style>'
  +'</Styles>'
  +'<Worksheet ss:Name="'+sheetName+'"><Table>'
  +'<Row>'+hRow+'</Row>\n'
  +dRows
  +'\n</Table></Worksheet></Workbook>';
const fileName=rawTitle.replace(/[^a-z0-9]/gi,'_')+'_'+ts+'.xls';
const base64=Buffer.from(xml,'utf-8').toString('base64');
return [{
  json:{...d,excel_file_name:fileName,excel_mime:'application/vnd.ms-excel',export_type:'excel',success:true},
